  ('optometrist-moex-02934', 'optometrist', 'optometrist-moex-107-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '當軟式散光隱形眼鏡採用動態穩定（dynamic stabilization）的設計時，那一種軸向的散光度數對鏡片轉動 影響（rotational effect）最小？', '["順散光", "逆散光", "45度斜散光", "135度斜散光"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:54+00:00", "source_pdf_sha1": "f15c3a22678d", "answer_pdf_sha1": "ef0155b35780", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "401", "s": "0804", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
