  ('optometrist-moex-02936', 'optometrist', 'optometrist-moex-107-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '以試戴片驗配硬式隱形眼鏡基弧7.80 mm/鏡片光學區直徑8.0 mm/鏡片直徑9.2 mm/度數-3.00 DS進行配 戴評估，鏡片中心有較大偏位，而且螢光染色發現表現暗色的中心區，周圍有極寬的螢光染，為求理想 配戴，應該調整試戴片的方式為：', '["改基弧為7.60 mm", "改鏡片光學區直徑為7.8 mm", "改鏡片直徑為9.0 mm", "改鏡片度數為-3.50 DS"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:54+00:00", "source_pdf_sha1": "f15c3a22678d", "answer_pdf_sha1": "ef0155b35780", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "401", "s": "0804", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02937', 'optometrist', 'optometrist-moex-107-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '高透氧硬式隱形眼鏡度數-3.00 DS/基弧 7.80 mm/光學區直徑 8.0 mm/鏡片直徑 9.4 mm，戴鏡驗光 （over-refraction）最佳視力1.0時的度數為+5.00 DS，插片頂點距離為12 mm。開立配鏡處方時，想改基 弧為7.90 mm，則此訂片的隱形眼鏡屈光度數為何？', '["+1.75 DS", "+2.00 DS", "+2.25 DS", "+2.75 DS"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:54+00:00", "source_pdf_sha1": "f15c3a22678d", "answer_pdf_sha1": "ef0155b35780", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "401", "s": "0804", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02938', 'optometrist', 'optometrist-moex-107-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '硬式隱形眼鏡初步評估，自動驗光檢測結果得右眼-4.5DS/-2.50DC×180，左眼-4.0DS/-2.75DC×180，角 膜弧度右眼43.00D@180/45.00D@090，左眼43.00D@180/45.25D@090，應如何選擇試戴片？（曲率半徑', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:54+00:00", "source_pdf_sha1": "f15c3a22678d", "answer_pdf_sha1": "ef0155b35780", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "401", "s": "0804", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 12, "answer_corrected": true, "flags": ["answer_corrected_skip_v1", "incomplete_options"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02939', 'optometrist', 'optometrist-moex-107-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '58 mm = 角膜弧度44.50 D；曲率半徑7.85 mm = 角膜弧度43.00 D）', '["右眼選用-3.00 DS/基弧7.58 mm/鏡片直徑9.4 mm 進行初次試戴", "左眼選用-3.00 DS/基弧7.85 mm/鏡片直徑9.4 mm 進行初次試戴", "雙眼皆選用-3.00 DS/基弧7.94 mm/鏡片直徑9.4 mm 進行初次試戴", "不建議驗配一般球面高透氧硬式隱形眼鏡"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:54+00:00", "source_pdf_sha1": "f15c3a22678d", "answer_pdf_sha1": "ef0155b35780", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "401", "s": "0804", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
